formulas.expression:
IF( {!$Record.Owner.Manager.Manager.Exclude_from_Email_Alerts__c} || NOT({!$Record.Owner.Manager.Manager.IsActive}
) , "" , 
IF( {!$Record.Owner.Manager.UserRole.DeveloperName}  = 'Director_ANZ_Sales_and_CSM', {!$Record.Owner.Manager.Email} , 
IF( OR( {!$Record.Owner.Manager.UserRole.DeveloperName} ='ENT_Resellers_Japan', {!$Record.Owner.Manager.UserRole.DeveloperName} ='ENT_Resellers_ROW' ), {!$Record.Owner.Manager.Email} , 
IF( OR( {!$Record.Owner.Manager.Manager.Manager.UserRole.DeveloperName} ='ENT_Resellers_Japan', {!$Record.Owner.Manager.Manager.Manager.UserRole.DeveloperName} ='ENT_Resellers_ROW' ), {!$Record.Owner.Manager.Manager.Manager.Email}, {!$Record.Owner.Manager.Manager.Email}) ) ) )

IF(
	CONTAINS({!$Record.Account.Name}, " - No Touch"), SUBSTITUTE({!$Record.Account.Name}, " - No Touch", ""),
	IF(
		CONTAINS({!$Record.Account.Name}, "- No Touch"), SUBSTITUTE({!$Record.Account.Name}, "- No Touch", ""),
		IF(
			CONTAINS({!$Record.Account.Name}, " -No Touch"), SUBSTITUTE({!$Record.Account.Name}, " -No Touch", ""),
			IF(
				CONTAINS({!$Record.Account.Name}, "-No Touch"), SUBSTITUTE({!$Record.Account.Name}, "-No Touch", ""),
				IF(
					CONTAINS({!$Record.Account.Name}, "No Touch"), SUBSTITUTE({!$Record.Account.Name}, "No Touch", ""),
					{!$Record.Account.Name}

				)
			)
		)
	)
)
